CREATE VIEW public.generation_progress AS
 SELECT c.number AS chapter_number,
    c.title AS chapter_title,
    s.code AS subtopic_code,
    s.name AS subtopic_name,
    cs.viable,
    count(q.id) FILTER (WHERE (q.status <> 'rejected'::public.question_status)) AS questions_done,
    (3 - count(q.id) FILTER (WHERE (q.status <> 'rejected'::public.question_status))) AS questions_remaining
   FROM (((public.chapter_subtopics cs
     JOIN public.chapters c ON ((c.id = cs.chapter_id)))
     JOIN public.subtopics s ON ((s.id = cs.subtopic_id)))
     LEFT JOIN public.questions q ON ((q.chapter_subtopic_id = cs.id)))
  WHERE (cs.viable = true)
  GROUP BY c.number, c.title, s.code, s.name, cs.viable
  ORDER BY c.number, s.code;


