CREATE VIEW public.generation_summary AS
 SELECT count(*) FILTER (WHERE (status <> 'rejected'::public.question_status)) AS total_questions,
    count(*) FILTER (WHERE (status = 'draft'::public.question_status)) AS drafts,
    count(*) FILTER (WHERE (status = 'review'::public.question_status)) AS in_review,
    count(*) FILTER (WHERE (status = 'approved'::public.question_status)) AS approved,
    count(*) FILTER (WHERE (status = 'rejected'::public.question_status)) AS rejected,
    (501 - count(*) FILTER (WHERE (status <> 'rejected'::public.question_status))) AS remaining
   FROM public.questions;


