    c.line_end,
    s.code AS subtopic_code,
    s.name AS subtopic_name,
    count(q.id) FILTER (WHERE (q.status <> 'rejected'::public.question_status)) AS done,
    (count(q.id) FILTER (WHERE (q.status <> 'rejected'::public.question_status)) + 1) AS next_question_number
   FROM (((public.chapter_subtopics cs
